The `debounce` function limits the rate at which a function is called, ensuring it's only executed after a specified delay has passed since the last invocation.

```javascript
/**
 * Debounces a function by the specified delay.
 * @param {function} func The function to debounce.
 * @param {number} delay The delay in milliseconds.
 * @returns {function} The debounced function.
 */
function debounce(func, delay) {
  let timeoutId;
  return function (...args) {
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
    timeoutId = setTimeout(() => {
      func(...args);
    }, delay);
  };
}

// Example usage:
const debouncedLogger = debounce((message) => console.log(message), 500);
debouncedLogger('Hello'); // Will log 'Hello' after 500ms
debouncedLogger('World'); // Will cancel the previous log and log 'World' after 500ms
```
